function buildStudentEmailText_(submission, includeCorrectAnswer) {
  const lines = [];
  lines.push('Maypure+ 신입교육 시험 결과');
  lines.push('이름: ' + (submission.candidate.name || '-'));
  lines.push('점수: ' + submission.score + '점');
  lines.push('정답: ' + submission.correct + ' / 오답: ' + submission.incorrect + ' / 검토: ' + (submission.review || 0));
  lines.push('');
  lines.push(includeCorrectAnswer ? '문항별 결과: 문항 / 내 선택 / 정답 / 결과' : '문항별 결과: 문항 / 내 선택 / 결과');
  (submission.details || []).forEach(function(detail) {
    const base = detail.number + '번 / ' + formatSelectedForEmail_(detail);
    const line = includeCorrectAnswer
      ? base + ' / 정답 ' + formatCorrectForEmail_(detail) + ' / ' + getResultLabel_(detail.status)
      : base + ' / ' + getResultLabel_(detail.status);
    lines.push(line);
  });
  return lines.join('\n');
}

