function formatSelectedForEmail_(detail) {
  if (detail.type === 'multiple') return detail.selectedNumber ? detail.selectedNumber + '번' : '미응답';
  return detail.selectedText || '미응답';
}

function formatCorrectForEmail_(detail) {
  if (detail.type === 'multiple') return detail.correctNumber ? detail.correctNumber + '번' : '-';
  return detail.correctText || '관리자 검토';
}

function getResultLabel_(status) {
  if (status === 'correct') return '정답';
  if (status === 'incorrect') return '오답';
  if (status === 'review') return '검토 필요';
  return '-';
}

function formatDate_(value) {
  if (!value) return '-';
  return Utilities.formatDate(new Date(value), Session.getScriptTimeZone(), 'yyyy-MM-dd HH:mm');
}

